package org.eclipse.rdf4j.sail.lmdb.sketch.omni;

import java.lang.foreign.MemorySegment;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

import org.apache.datasketches.common.SketchesArgumentException;

/** Convenience factory and query methods for the OmniSketch family. */
public final class OmniSketches {
	private OmniSketches() {
	}

	/** Returns a new OmniSketch builder. */
	public static OmniSketchBuilder builder() {
		return OmniSketch.builder();
	}

	/** Heapifies a compact sketch from bytes. */
	public static CompactOmniSketch heapify(final byte[] bytes) {
		return CompactOmniSketch.heapify(bytes);
	}

	/** Heapifies a compact sketch from a Java FFM MemorySegment. */
	public static CompactOmniSketch heapify(final MemorySegment segment) {
		return CompactOmniSketch.heapify(segment);
	}

	/** Wraps a compact sketch from a Java FFM MemorySegment. */
	public static CompactOmniSketch wrap(final MemorySegment segment) {
		return CompactOmniSketch.wrap(segment);
	}

	/** Builds an equality predicate. */
	public static OmniSketchPredicate equalTo(final Object value) {
		return OmniSketchPredicate.equalTo(value);
	}

	/** Builds an IN predicate over long values. */
	public static OmniSketchPredicate anyOfLongs(final long... values) {
		return OmniSketchPredicate.anyOfLongs(values);
	}

	/**
	 * Estimates the intersection of predicates over multiple compatible OmniSketch dimensions.
	 *
	 * <p>
	 * The iteration orders of {@code sketches} and {@code predicates} must match: the first predicate applies to the
	 * first sketch, the second predicate to the second sketch, and so on.
	 * </p>
	 */
	public static OmniSketchEstimate intersection(final Iterable<? extends OmniSketch> sketches,
			final Iterable<OmniSketchPredicate> predicates) {
		final Iterator<? extends OmniSketch> sketchIt = sketches.iterator();
		final Iterator<OmniSketchPredicate> predicateIt = predicates.iterator();
		final List<OmniSketchSummary> summaries = new ArrayList<>();
		OmniSketch first = null;
		while (sketchIt.hasNext() && predicateIt.hasNext()) {
			final OmniSketch sketch = sketchIt.next();
			final OmniSketchPredicate predicate = predicateIt.next();
			if (first == null) {
				first = sketch;
			} else {
				first.checkCompatible(sketch);
			}
			summaries.add(sketch.summary(predicate));
		}
		if (sketchIt.hasNext() || predicateIt.hasNext()) {
			throw new SketchesArgumentException("The number of sketches must equal the number of predicates");
		}
		return OmniSketchSummary.intersectionEstimate(summaries);
	}
}
